import{_ as t,c as a,o as n,j as s}from"./chunks/framework.BvcDoAct.js";const R=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"ja-jp/Management2/PART2/3.md","filePath":"ja-jp/Management2/PART2/3.md"}'),r={name:"ja-jp/Management2/PART2/3.md"};function S(o,e,A,B,I,p){return n(),a("div",null,[...e[0]||(e[0]=[s("p",null,"►2022/11 BE:FIRST紅白歌合戦出場の意味とAAA時代に感じたこと #感覚と実態#勢いの加速#ビジョンの推進力#紅白歌合戦#BEFIRST 「今は、“実態”や“実績”を考えるうえで、数字以外のものが必要な時代だと思っている」 BE:FIRSTは2022年12月31日、『第73回NHK紅白歌合戦』に初出場を果 たす。設立3年目のBMSGに所属する、デビュー1周年のグループが国民的 番組に出場することは、“時代が動いている”ことの象徴と言っても過言で ないだろう。自身もAAAのメンバーとして過去7回出場しているSKY-HIだが、 紅白に出ることの意義をどう捉えているのか。 BE:FIRSTにとって紅白歌合戦の出場は、ヒットしている「感 覚」に「実態」を伴わせられるまたとない機会だと考えています。 AAAの場合は、ヒットしている「感覚」がない状態から出場して いて、「自分らがここにいていいのだろうか」という感情もゼロでは なかったんです。これといった成績もありませんでしたし。それにもかかわらず「紅白出場」という“権威”による「実態」を得たことで世間の風向きが変わっていく「感覚」は感じました。 人間って、「これは人気があります」と言われたところへおのずと集まっていく性質があると思うんです。俗に言うバンドワゴン効果ですかね。AAAの時は紅白歌合戦さんに出場させていただたこ とで、そうしたプラスの効果を感じました。 一方でBE:FIRSTの場合は、その逆かもしれません。今、ありがたいことに「BE:FIRST,きてるよね」といろいろな方に言ってい ただし、単曲のヒットもあるのですが、それはまだ「感覚」なん です。ただ、今は、「実態」や「実績」を考えるうえで数字以外のものが必要な時代だと思っているのですが、「感覚」と「実態」 をつなげるものとして、紅白歌合戦さんという圧倒的な権威は、BE:FIRSTにとって良い状況をさらに加速させられるのではないかと提 えています。 いいものを見せれば結果は付いてくる 紅白の選出に先立つ10月15日には、NHKの音楽番組『Venue101』のスピンオフ特番『Venue101PresentsBE:FIRSTLIVESPECIAL』が組まれたが、放送前にはSKY-HIが珍しくファンに盛り上げをあおっていた印象があった。 確かにあおっていましたし、珍しいことだと思います(笑)。たび たび話すことですが、BMSGの起業当初から音楽業界への危機感を強く発信してきたことで、業界の方や権威側から敵対視される可能性があるという覚悟はしていたんです。でも蓋を開ければそうではなく、ありがたいことに想像以上に応援してくださる人や、好意的な声が多かったんです。その中で確実に『Venue101』さんのチームはBMSG全体を応援してくださっていると感じていました。これだけたくさんのアーティストが活躍するなかで紅白に誰を選ぶかは、結局「誰を出したいか」だと思うんです。だとしたら、もしかすると『Venue101PresentsBE:FIRSTLIVESPECIAL』は何か自分たちにチャンスを与えてくださったのかもしれないと解釈 48 し、その期待に応えることはすごく大事なことだと感じました。いいものを見せることができれば、おのずと結果は付いてくるのかもしれないな、と。(紅白出場は)2022年頭から狙っていたことなので、もちろん他の話も統合しての自分の肌感覚ではありますが。 どこの企業の資本も入っていない、一個人として会社を設立し て2年、BE:FIRSTがデビューして1年で、“権威”とお仕事でき るのもこれまでの芸能にはなかったことです。本当に歴史的なこと だと思います。今後のBMSGが掲げるビジョンの推進力でもあり、時代を変えることにもさらにつながっていくのではないかと確信して います。",-1)])])}const T=t(r,[["render",S]]);export{R as __pageData,T as default};
